import React, { useEffect } from 'react'
import $ from "jquery";
const Header = () => {
  useEffect(()=>{
    var ssMobileMenu = function () {
      var toggleButton = $(".header-menu-toggle"),
        nav = $(".header-nav-wrap");

      toggleButton.on("click", function (event) {
        event.preventDefault();

        toggleButton.toggleClass("is-clicked");
        nav.slideToggle();
      });

      if (toggleButton.is(":visible")) nav.addClass("mobile");

      $(window).on("resize", function () {
        if (toggleButton.is(":visible")) nav.addClass("mobile");
        else nav.removeClass("mobile");
      });

      nav.find("a").on("click", function () {
        if (nav.hasClass("mobile")) {
          toggleButton.toggleClass("is-clicked");
          nav.slideToggle();
        }
      });
    };
    ssMobileMenu()
})

  return (
    <header className="s-header">
      <div className="header-logo">
        <a className="site-logo" href="/">
          <img src="images/logo.svg" alt="Homepage" />
        </a>
      </div>

      <nav className="header-nav-wrap">
        <ul className="header-main-nav">
          <li className="current">
            <a className="smoothscroll" href="#intro" title="intro">
              Intro
            </a>
          </li>
          <li>
            <a className="smoothscroll" href="#about" title="about">
              About
            </a>
          </li>
          <li>
            <a className="smoothscroll" href="#services" title="services">
              Services
            </a>
          </li>
          <li>
            <a className="smoothscroll" href="#works" title="works">
              Works
            </a>
          </li>
          <li>
            <a className="smoothscroll" href="#contact" title="contact us">
              Say Hello
            </a>
          </li>
        </ul>

        <ul className="header-social">
          <li>
            <a href="https://www.facebook.com/caliph.bin.kabir">
              <i className="fab fa-facebook-f" aria-hidden="true"></i>
            </a>
          </li>
          <li>
            <a href="https://www.youtube.com/channel/UC1sUr3ArLFO2aMj3IVNV7nQ">
              <i className="fab fa-youtube" aria-hidden="true"></i>
            </a>
          </li>
          <li>
            <a href="#0">
              <i className="fab fa-linkedin" aria-hidden="true"></i>
            </a>
          </li>
          <li>
            <a href="#0">
              <i className="fab fa-github" aria-hidden="true"></i>
            </a>
          </li>
        </ul>
      </nav>

      <a className="header-menu-toggle" href="#">
        <span>Menu</span>
      </a>
    </header>
  );
}

export default Header