import React, { useState, useCallback } from "react";
import Gallery from "react-photo-gallery";
import Carousel, { Modal, ModalGateway } from "react-images";
const Works = () => {
  const [currentImage, setCurrentImage] = useState(0);
  const [viewerIsOpen, setViewerIsOpen] = useState(false);

  const openLightbox = useCallback((event, { photo, index }) => {
    setCurrentImage(index);
    setViewerIsOpen(true);
  }, []);

  const closeLightbox = () => {
    setCurrentImage(0);
    setViewerIsOpen(false);
  };
  const photos = [
    {
      src: "images/portfolio/portfolio-01.png",
      width: 4,
      height: 3,
    },
    {
      src: "images/portfolio/portfolio-02.png",
      width: 4,
      height: 3,
    },
    {
      src: "images/portfolio/portfolio-03.jpg",
      width: 4,
      height: 3,
    },
    {
      src: "images/portfolio/portfolio-04.png",
      width: 4,
      height: 3,
    },
    {
      src: "images/portfolio/portfolio-05.png",
      width: 4,
      height: 3,
    },
    {
      src: "images/portfolio/portfolio-06.jpg",
      width: 4,
      height: 3,
    },
  ];
  return (
    <section id="works" className="s-works target-section">
      <div
        className="row heading-block heading-block--center"
        data-aos="fade-up"
      >
        <div className="column large-full">
          <h2 className="section-heading section-heading--centerbottom">
            Selected Works
          </h2>
          <p className="section-desc">
            Here are some of my selected works I have done lately. Feel free to
            check them out.
          </p>
        </div>
      </div>
      <Gallery photos={photos} direction={"row"} onClick={openLightbox} />
      <ModalGateway>
        {viewerIsOpen ? (
          <Modal onClose={closeLightbox}>
            <Carousel
              currentIndex={currentImage}
              views={photos.map((x) => ({
                ...x,
                srcset: x.srcSet,
                caption: x.title,
              }))}
            />
          </Modal>
        ) : null}
      </ModalGateway>
    </section>
  );
};

export default Works;
